sys_variable_value.value:
(function execute(inputs, outputs) {
  var certificateService = new CertificateService();
  certificateService.saveCertificate({
    serialNumber: inputs.serialNumber,
    deliveryFormat: inputs.deliveryFormat,
    certificate: inputs.certificate,
  }, inputs.certificateRequestGr.getValue("sys_id"));
})(inputs, outputs);

